const api = 'http://localhost:8787'
const stamp = Date.now().toString(36)
// 1. sign-up
const su = await fetch(`${api}/api/auth/sign-up/email`, {
  method: 'POST', headers: {'content-type':'application/json'},
  body: JSON.stringify({ email: `probe-${stamp}@sofar.test`, password: `pw-${stamp}-long-enough`, name: 'Probe' })
})
console.log('sign-up:', su.status)
const suBody = await su.json().catch(() => ({}))
const session = su.headers.get('set-auth-token') ?? suBody.token
console.log('session token present:', !!session)
// 2. device code
const dc = await fetch(`${api}/api/auth/device/code`, {
  method: 'POST', headers: {'content-type':'application/json'},
  body: JSON.stringify({ client_id: 'sofar-cli' })
})
const code = await dc.json()
console.log('device/code:', dc.status, JSON.stringify(code).slice(0, 200))
// 3. claim
const claim = await fetch(`${api}/api/auth/device?user_code=${encodeURIComponent(code.user_code)}`, {
  headers: { authorization: `Bearer ${session}` }
})
console.log('claim:', claim.status, (await claim.text()).slice(0, 300))
// 4. approve
const approve = await fetch(`${api}/api/auth/device/approve`, {
  method: 'POST',
  headers: { authorization: `Bearer ${session}`, 'content-type': 'application/json' },
  body: JSON.stringify({ userCode: code.user_code })
})
console.log('approve:', approve.status, (await approve.text()).slice(0, 300))
// 5. token poll
const tok = await fetch(`${api}/api/auth/device/token`, {
  method: 'POST', headers: {'content-type':'application/json'},
  body: JSON.stringify({ grant_type: 'urn:ietf:params:oauth:grant-type:device_code', device_code: code.device_code, client_id: 'sofar-cli' })
})
console.log('token:', tok.status, (await tok.text()).slice(0, 200))
EOF
node probe-device.mjs

